INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Advanced candidate search$q$, $q$Search LinkedIn's full member network with dozens of filters covering skills, experience, seniority, company, industry, and location.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$InMail messaging$q$, $q$Send direct messages to candidates outside your existing network, with monthly InMail credits that scale by plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Projects and pipelines$q$, $q$Organize candidates by open role, add notes and ratings, and move people through custom pipeline stages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Recommended Matches$q$, $q$AI-assisted suggestions that surface additional candidates similar to those already added to a project.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Team collaboration$q$, $q$Share talent pools, notes, and candidate feedback across recruiters and hiring managers on the same account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$ATS integrations$q$, $q$Sync candidate and requisition data with applicant tracking systems like Greenhouse, Workday, and SmartRecruiters.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Talent pool insights$q$, $q$View aggregate data on candidate pools, such as location and skills distribution, to gauge market supply for a role.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Saved searches and alerts$q$, $q$Save complex searches and receive alerts when new candidates matching the criteria join LinkedIn or update their profile.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Reporting and usage analytics$q$, $q$Track InMail response rates, pipeline activity, and recruiter usage across the team for license and performance oversight.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Access to LinkedIn's large, frequently updated professional member base$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Deep, granular search filters beyond what a standard LinkedIn account offers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$InMail lets recruiters reach passive candidates with no prior connection$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Project-based pipelines make it easy to organize candidates per open role$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Integrates with major ATS platforms already used by talent acquisition teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Enterprise Corporate pricing is quote-based and can be costly per seat$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Not a full applicant tracking system, so it's usually paired with another tool$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$InMail credits and search results depend on candidates having an active, current LinkedIn profile$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Response rates can be inconsistent, especially with generic outreach messages$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Annual contract and per-seat licensing make it less flexible for fluctuating hiring needs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$What is LinkedIn Recruiter used for?$q$, $q$It is used by talent acquisition teams and recruiting agencies to search LinkedIn's member network for candidates, message them via InMail, and organize prospects into pipelines for open roles.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$How much does LinkedIn Recruiter cost?$q$, $q$The full Recruiter Corporate plan is quote-based enterprise pricing set through LinkedIn's sales team, while the lighter self-serve Recruiter Lite plan is available at a lower monthly price for individual recruiters.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Is LinkedIn Recruiter the same as LinkedIn Recruiter Lite?$q$, $q$No. Recruiter Lite is a lower-cost, individual-focused plan with fewer InMail credits and search filters, while Recruiter (Corporate) offers deeper search, more InMail, and team collaboration features.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Does LinkedIn Recruiter replace an applicant tracking system?$q$, $q$No. It is primarily a sourcing and search tool; most organizations use it alongside a separate ATS for managing applications, offers, and onboarding.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Can LinkedIn Recruiter integrate with other hiring tools?$q$, $q$Yes, it integrates with a number of major ATS platforms so candidate and requisition data can flow between systems.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Proactive sourcing for hard-to-fill roles$q$, $q$Recruiters use advanced search filters to identify passive candidates with niche skills who are not actively applying to jobs.$q$, $q$In-house corporate recruiters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Multi-client agency sourcing$q$, $q$Agency recruiters run parallel searches and projects across multiple client accounts, tracking candidates separately for each search.$q$, $q$Recruitment and executive search agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Building talent pipelines ahead of demand$q$, $q$Teams proactively source and nurture candidate pools for anticipated future roles rather than starting from scratch when a requisition opens.$q$, $q$Talent acquisition leaders$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Collaborative hiring with stakeholder feedback$q$, $q$Recruiters share candidate profiles and notes within a project so hiring managers can review and weigh in before outreach or interviews.$q$, $q$Hiring managers and recruiting teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Recruiter Lite$q$, $q$From approximately $170/month$q$, $q$Monthly or annual$q$, $q$["Expanded search filters beyond a standard LinkedIn account","Monthly InMail credits for individual recruiters","Candidate list and basic project organization","Designed for individual, lower-volume sourcing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Recruiter Corporate$q$, $q$Custom pricing (contact sales)$q$, $q$Annual contract$q$, $q$["Full-depth advanced search across LinkedIn's member network","Higher monthly InMail allowance per seat","Team collaboration, shared talent pools, and pipeline projects","ATS integrations and team-level reporting"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LinkedIn Recruiter is the enterprise-grade sourcing and hiring platform built on top of LinkedIn's professional network, part of the broader LinkedIn Talent Solutions suite owned by Microsoft. Rather than being a standalone applicant tracking system, it functions as a deep search and outreach layer that sits on top of LinkedIn's member graph, giving in-house recruiters and agency teams a way to find, evaluate, and message candidates who may never apply to a job posting directly.$q$, $q$The core value proposition is access: LinkedIn Recruiter unlocks advanced search filters, full-profile visibility beyond a recruiter's immediate network, InMail credits for messaging people outside existing connections, and project-based pipeline organization so hiring teams can track candidates through a search from first contact to offer. It is commonly used alongside, rather than instead of, a dedicated ATS, since many organizations integrate LinkedIn Recruiter data into systems like Greenhouse, Workday, or SmartRecruiters.$q$, $q$LinkedIn Recruiter is sold in tiers, most notably the self-serve Recruiter Lite plan for individual recruiters and the sales-negotiated Recruiter Corporate plan for larger teams, with pricing and InMail allowances scaling accordingly. Because it draws on LinkedIn's member base, its main differentiator versus other sourcing tools is the sheer breadth and freshness of professional profile data, updated directly by the people it describes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$who-linkedin-recruiter-is-for$q$, $q$Who LinkedIn Recruiter Is For$q$, 2, ARRAY[$q$LinkedIn Recruiter is built primarily for in-house corporate talent acquisition teams that need to fill a steady volume of roles across departments and need to proactively reach passive candidates who are not actively browsing job boards. Talent acquisition leads at mid-size and large companies are typically the ones negotiating and administering the Corporate license for their teams.$q$, $q$Recruitment agencies and executive search firms are another core audience, using LinkedIn Recruiter to source across many clients and industries at once, leaning heavily on saved searches, InMail, and pipeline/project features to manage parallel searches for different employers. High-volume technical and specialized recruiting functions, where candidates are scarce and rarely respond to inbound applications, also benefit from the tool's search depth.$q$, $q$Smaller teams or solo recruiters who need occasional outreach but not full enterprise search depth are often better served by the lower-cost Recruiter Lite tier rather than the full Corporate product, since Lite still provides InMail and expanded search at a fraction of the cost.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small companies or startups hiring only a handful of roles per year will likely find LinkedIn Recruiter's enterprise pricing hard to justify, since the annual per-seat cost of the Corporate tier can exceed what a small hiring budget can absorb relative to the number of hires it produces. Recruiter Lite or organic LinkedIn job postings are usually a more proportionate starting point.$q$, $q$Teams that already rely on inbound applicant flow, employee referrals, or a strong existing candidate database may not need LinkedIn Recruiter's outbound sourcing strength, since its core value is finding and messaging people who are not already in a pipeline. Organizations without dedicated recruiter headcount to actually run searches and follow up on InMail responses often see poor return on the license.$q$, $q$Buyers looking for a full end-to-end applicant tracking system with offer management, background checks, or onboarding workflows should look elsewhere, as LinkedIn Recruiter is a sourcing and search tool rather than a system of record for the hiring process, and it is typically paired with a separate ATS rather than replacing one.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of LinkedIn Recruiter is its advanced search engine, which layers dozens of filters, including years of experience, skills, seniority, company, industry, and location, on top of LinkedIn's full member graph rather than the limited view available to a standard LinkedIn account. This lets recruiters build precise talent pools far beyond their own first- and second-degree connections.$q$, $q$InMail messaging is the primary outreach mechanism, allowing recruiters to contact candidates directly even without a prior connection, with monthly credit allowances that scale by plan tier. Projects and pipelines let teams organize candidates by role, add notes and ratings, tag colleagues, and move people through stages, while Recommended Matches and similar AI-assisted suggestions surface candidates who resemble people already added to a project.$q$, $q$Team collaboration features, shared talent pools, integration with major ATS platforms, and reporting on pipeline and search activity round out the toolset, giving talent acquisition leaders visibility into how their team is sourcing and where candidates are getting stuck in the process.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$the-linkedin-recruiter-experience$q$, $q$The LinkedIn Recruiter Experience$q$, 2, ARRAY[$q$Using LinkedIn Recruiter feels like an extension of the familiar LinkedIn interface, but with far more search depth and a project-based workspace layered on top. Recruiters typically start a search, save it, and then move promising profiles into a project where they can leave notes, apply candidate stages, and loop in hiring managers or colleagues for feedback before reaching out.$q$, $q$Because it is built on live LinkedIn profile data, the experience benefits from information candidates keep current themselves, such as recent job changes, endorsements, and activity, which can make outreach timing and personalization easier than with a static resume database. The tradeoff is that recruiters are working within LinkedIn's interface and data model rather than a fully customizable in-house tool, so workflows outside of search, messaging, and basic pipeline tracking usually happen in a connected ATS instead.$q$, $q$Response rates and overall effectiveness depend heavily on message quality and search precision, and larger teams report that the platform rewards recruiters who invest time in refining boolean-style searches and personalizing InMail rather than sending generic templates at scale. Onboarding for new users typically involves LinkedIn-provided training resources and, for enterprise customers, a dedicated customer success contact to help ramp up usage.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Customizable chat widget$q$, $q$Brandable chat window with configurable colors, greetings, and placement that can be embedded on any website.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Visitor tracking$q$, $q$See who is on your site in real time, including the pages they've viewed and where they came from, to prioritize outreach.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Chat routing and tagging$q$, $q$Route conversations to the right department or agent and organize chats with tags for easier reporting and follow-up.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Canned responses$q$, $q$Save and reuse pre-written replies to answer common questions faster and keep responses consistent across agents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Ticketing and archives$q$, $q$Conversations that can't be resolved live are preserved in a searchable archive so agents can follow up later.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Reporting and analytics$q$, $q$Dashboards covering chat volume, response times, agent performance, and customer satisfaction ratings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Integrations marketplace$q$, $q$Pre-built connections to e-commerce platforms, CRMs, help desks, and marketing tools to fit into existing workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Mobile apps$q$, $q$iOS and Android apps let agents respond to chats and monitor queues away from their desks.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$API and webhooks$q$, $q$Developer tools for building custom integrations, automations, and data syncs beyond the built-in connectors.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Fast, easy setup with a widget that can be embedded on a website in minutes$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Clean, responsive agent interface that keeps common tasks quick$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Strong visitor tracking that helps sales teams start proactive conversations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Large library of integrations with e-commerce, CRM, and marketing tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Solid reporting on response times, chat volume, and customer satisfaction$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$No permanent free plan, only a time-limited free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Per-agent pricing can get expensive as support teams scale up$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Advanced automation and full ticketing require separate companion products$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Some integrations and automation rules take extra time to configure well$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Primarily focused on website chat rather than a single unified omnichannel inbox$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Does LiveChat offer a free plan?$q$, $q$LiveChat does not offer a permanent free plan, but it does provide a free trial period so teams can test the product before subscribing.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$How much does LiveChat cost?$q$, $q$LiveChat is sold on a per-agent monthly subscription with several tiers; pricing starts at roughly $20 per agent per month when billed annually, with higher tiers unlocking more automation, reporting, and integrations.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Who makes LiveChat?$q$, $q$LiveChat is made by Text (formerly LiveChat Software), a company founded in 2002 and headquartered in Wroc≈Çaw, Poland.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Can LiveChat integrate with my CRM or e-commerce platform?$q$, $q$Yes, LiveChat offers a large marketplace of integrations with popular CRM, e-commerce, help desk, and marketing tools, along with an API for custom connections.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Is there a mobile app for LiveChat?$q$, $q$Yes, LiveChat provides iOS and Android apps so agents can respond to chats and monitor activity while away from their desktop.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Pre-sales lead qualification$q$, $q$Use visitor tracking and proactive greetings to start conversations with visitors showing buying intent before they leave the site.$q$, $q$Sales teams at SaaS and B2B companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$E-commerce support at checkout$q$, $q$Answer product and shipping questions in real time to reduce cart abandonment during the purchase process.$q$, $q$Online retailers and e-commerce brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Tiered customer support$q$, $q$Route incoming chats by department or issue type and escalate unresolved conversations into the ticket archive for follow-up.$q$, $q$Customer support teams handling moderate to high chat volume$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Multi-agent team collaboration$q$, $q$Transfer chats between agents, tag conversations, and monitor team performance from a shared supervisor dashboard.$q$, $q$Growing support or success teams with multiple agents$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Starter$q$, $q$$20/agent/month$q$, $q$Billed annually$q$, $q$["Basic chat widget","Chat history (limited)","Ticket form","Basic reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Team$q$, $q$$41/agent/month$q$, $q$Billed annually$q$, $q$["Full chat history","Work scheduler","Advanced targeting rules","Basic integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Business$q$, $q$$59/agent/month$q$, $q$Billed annually$q$, $q$["Advanced reporting","Staffing prediction","Data export","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["Dedicated account manager","Custom onboarding","Enhanced security options","Custom agent seat allocation"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LiveChat is a customer messaging and help desk platform built around a live chat widget that businesses embed on their websites to talk to visitors in real time. Developed by Text (formerly LiveChat Software), a Polish company based in Wroc≈Çaw that has been building the product since 2002, LiveChat has grown from a simple chat box into a broader customer service suite that also handles tickets, chatbots, and integrations with e-commerce and CRM tools.$q$, $q$At its core, LiveChat gives support and sales teams a single agent app for handling conversations that start on the website, in email, or through connected messaging channels. Chats can be routed by department, tagged, monitored for sentiment, and handed off between agents, while supervisors get visibility into queue length, response times, and customer satisfaction ratings from a shared dashboard.$q$, $q$LiveChat is part of a wider product family from the same company, which also makes ChatBot for automation and HelpDesk for ticketing, and it is commonly bought either as a standalone chat tool or alongside those companion products for teams that want a more complete customer service stack.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$who-livechat-is-for$q$, $q$Who LiveChat Is For$q$, 2, ARRAY[$q$LiveChat is best suited to small and mid-sized businesses that rely on their website as a primary channel for sales inquiries or support, including SaaS companies, online retailers, and service providers who want visitors to get quick answers before they abandon a purchase or sign-up.$q$, $q$Support teams that need structure around chat volume are a good fit, since LiveChat offers routing rules, canned responses, tagging, and reporting that help teams stay organized as ticket and chat counts grow beyond what a single agent can track manually.$q$, $q$It also works well for sales-driven organizations that want to use chat proactively, since features like visitor tracking, greetings triggered by page behavior, and integrations with CRM and e-commerce platforms let sales teams start conversations with qualified leads rather than only reacting to inbound messages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very early-stage businesses or hobby sites with minimal traffic may find LiveChat's per-agent subscription pricing hard to justify, since there is no permanent free plan and the value of the tool scales with chat volume the business doesn't yet have.$q$, $q$Teams looking for an all-in-one omnichannel platform that natively unifies phone, social DMs, and email under one roof without extra add-ons may prefer a broader customer service suite, since LiveChat's core strength is website chat and its help desk and chatbot capabilities are separate products from the same company.$q$, $q$Organizations with strict data residency or highly specialized compliance requirements outside what LiveChat publishes should confirm the platform's certifications directly, since general-purpose live chat tools are not always built around a single industry's regulatory checklist.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The centerpiece of LiveChat is its customizable chat widget, which can be styled to match a brand, set to greet visitors automatically, and configured to route conversations to the right team based on the page a visitor is on or the department they select.$q$, $q$Agents work from a unified app that shows visitor context such as location, browsing history on the site, and past conversations, alongside tools like canned responses, file sharing, chat tags, and the ability to transfer or loop in other agents mid-conversation. Supervisors get reporting on chat volume, response and resolution times, and customer satisfaction surveys.$q$, $q$LiveChat also connects to a large library of integrations spanning e-commerce platforms, CRMs, help desks, and marketing tools, and it exposes an API and webhooks for teams that want to build custom workflows, alongside mobile apps so agents can respond to chats away from their desks.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$the-livechat-experience$q$, $q$The LiveChat Experience$q$, 2, ARRAY[$q$Setting up LiveChat typically takes a small install snippet added to a website, after which the widget appears with sensible defaults that most teams can start using within minutes; more advanced configuration, like routing rules and eligibility criteria for automatic greetings, is layered on afterward.$q$, $q$Day to day, agents describe the interface as clean and responsive, with the chat window, ticket-like archive, and reporting dashboards organized in a way that keeps repetitive tasks fast, though some teams report a learning curve when configuring more advanced automation or when connecting several third-party integrations at once.$q$, $q$Overall, the experience leans toward a tool that does live chat and light help desk work well out of the box, with the option to extend into fuller automation and ticketing by adding the company's companion products, ChatBot and HelpDesk, as needs grow.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
