INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Live, on-demand, and automated webinars$q$, $q$Run webinars live, repurpose recordings as on-demand replays, or schedule them to play automatically on a recurring cadence.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$No-download browser access$q$, $q$Hosts and attendees join directly from a link in any modern browser, with no software installation required.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Registration pages and email builder$q$, $q$Create branded registration landing pages and automated confirmation, reminder, and follow-up email sequences.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Engagement tools$q$, $q$Polls, live Q&A, chat, call-to-action buttons, and handouts keep attendees active during sessions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Analytics and reporting$q$, $q$Track registrations, attendance, watch time, and engagement metrics per event to gauge performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$CRM and marketing automation integrations$q$, $q$Native connections to HubSpot, Salesforce, Marketo, and Zapier sync attendee data into existing workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Meetings$q$, $q$Lightweight one-to-one or small-group video meetings for demos, onboarding, and customer calls.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Recording and clips$q$, $q$Automatically record sessions and create shorter clips for on-demand distribution or social sharing.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$API access$q$, $q$Build custom integrations around registration, attendance, and engagement data for teams with specific workflow needs.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$No downloads required for hosts or attendees, reducing join friction$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Combines webinar hosting, registration, email, and analytics in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Genuinely usable free plan for testing the product before buying$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Strong native integrations with popular CRM and marketing automation tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Clean, intuitive interface for building and managing events$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Usage-based, attendee-credit pricing can become expensive for high-volume programs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Free plan caps session length and attendee count fairly low$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Add-on and enterprise pricing generally require a sales conversation rather than transparent listing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Less suited to large-scale broadcast production compared to dedicated streaming tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Advanced customization options may feel limited next to more production-heavy webinar platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Does Livestorm require attendees to download an app?$q$, $q$No. Livestorm runs entirely in the browser, so hosts and attendees join by clicking a link without installing any software.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Is there a free version of Livestorm?$q$, $q$Yes, Livestorm offers a free plan with core webinar and meeting features, though it limits attendee count and session duration compared to paid plans.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$How does Livestorm pricing work?$q$, $q$Livestorm uses an attendee-credit, usage-based pricing model where cost scales with the number of unique attendees across live, replay, and on-demand sessions, in addition to tiered monthly plans.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Can Livestorm integrate with my CRM?$q$, $q$Yes, Livestorm offers native integrations with platforms like HubSpot, Salesforce, and Marketo, plus Zapier and an API for custom connections.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$What is Livestorm best used for?$q$, $q$Livestorm is best suited for B2B marketing webinars, product demos, and customer-facing meetings where an easy, no-install join experience and integrated analytics matter most.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Demand-generation webinars$q$, $q$Marketing teams build registration pages, schedule reminder emails, and host live webinars to generate and nurture leads.$q$, $q$B2B marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Product demos and sales calls$q$, $q$Sales teams use Livestorm meetings to run live product demonstrations with prospects without requiring any software installation.$q$, $q$Sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Customer onboarding and training$q$, $q$Customer success teams host recurring onboarding sessions and training webinars, reusing recordings as on-demand resources.$q$, $q$Customer success teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Internal and external events$q$, $q$Organizations run town halls, panel discussions, and multi-session virtual events with unified registration and analytics.$q$, $q$Event organizers and HR/communications teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Free$q$, $q$Free$q$, $q$N/A$q$, $q$["Unlimited webinars and moderators","Limited live attendees per session","Short session duration cap","Registration page and email builder basics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Pro$q$, $q$From around $110/month (lower with annual billing)$q$, $q$Monthly or annual$q$, $q$["Higher attendee and active contact limits","Longer session durations","Unlimited team members","CRM and marketing automation integrations","Advanced analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual (custom)$q$, $q$["Custom attendee volume and add-ons","Dedicated support and onboarding","Advanced security and admin controls","Custom integrations and API support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Livestorm is a browser-based video engagement platform built for webinars, virtual events, product demos, and online meetings. Founded in Paris in 2016, the company set out to remove the friction that plagued traditional webinar software: no downloads, no plugins, and a single link that works on any device with a modern browser.$q$, $q$The platform combines live, on-demand, and automated (evergreen) webinars with built-in registration pages, email sequences, and analytics, positioning itself as an all-in-one engagement suite rather than a bare-bones streaming tool. Marketing and revenue teams use it to run demand-generation webinars, while customer success and sales teams use the meeting features for demos and onboarding calls.$q$, $q$Livestorm integrates with common marketing and CRM stacks such as HubSpot, Salesforce, Marketo, and Zapier, and exposes an API for teams that want to build custom workflows around registration, attendance, and engagement data. It has grown from a small Paris startup into a widely used tool across Europe and North America, particularly among B2B SaaS marketing teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$who-livestorm-is-for$q$, $q$Who Livestorm Is For$q$, 2, ARRAY[$q$Livestorm suits B2B marketing teams that run recurring webinars as part of their demand-generation motion, since registration pages, reminder emails, and follow-up sequences are built into the same workflow rather than bolted on through a separate tool.$q$, $q$It also works well for customer success, sales, and product teams that need a lightweight, no-install meeting experience for demos, onboarding sessions, or training, where asking a prospect to download software would add friction to the conversation.$q$, $q$Organizations that value integrated analytics and CRM syncing benefit most, since Livestorm's reporting on registrations, attendance, and engagement can flow directly into a marketing or sales system of record without manual exports.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams running very large-scale broadcasts with thousands of concurrent live attendees, or those needing advanced production features like multi-camera switching and broadcast-grade streaming, may find dedicated event-production or streaming platforms a better fit.$q$, $q$Budget-conscious teams that host high-volume, low-cost webinars should look closely at the usage-based, attendee-credit pricing model, since costs scale with audience size and can climb quickly compared to flat-fee competitors for high-attendance programs.$q$, $q$Companies that only need a basic, occasional meeting tool without registration pages, marketing automation, or analytics may find Livestorm more capability (and cost) than they actually need, and could be better served by a simpler video conferencing app.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Livestorm supports live, on-demand, and automated webinars from a single dashboard, letting teams repurpose one event across formats without re-recording or rebuilding registration flows each time.$q$, $q$Built-in registration page and email builders, along with engagement tools like polls, Q&A, chat, call-to-action buttons, and handout downloads, let hosts capture leads and keep attendees engaged without leaving the platform.$q$, $q$Reporting and integrations round out the feature set: attendance and engagement analytics, recording and clip tools, and native connections to CRM and marketing automation platforms via HubSpot, Salesforce, Marketo, and Zapier, plus an API for custom data flows.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$the-livestorm-experience$q$, $q$The Livestorm Experience$q$, 2, ARRAY[$q$Because everything runs in the browser, joining a Livestorm session is typically a one-click experience for attendees, which reduces drop-off compared to tools that require software installation, especially for external prospects and customers.$q$, $q$The host-side interface groups event creation, engagement tools, and reporting in one place, so marketers can build a registration page, schedule reminder emails, and review post-event analytics without switching between separate products.$q$, $q$New users generally find the setup intuitive, though the shift to attendee-based, usage pricing means teams should model their expected audience size carefully when comparing the free plan against paid tiers to avoid surprises as programs scale.$q$]::text[], 4);
