INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$No-Code Workflow Builder$q$, $q$A drag-and-drop designer for building risk, compliance, and audit workflows, forms, and automations without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Application Library$q$, $q$Pre-built, customizable Applications covering common GRC use cases that teams can deploy as a starting point instead of building from scratch.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Enterprise Risk Management$q$, $q$Tools for identifying, scoring, and monitoring enterprise risks and linking them to relevant controls and mitigation plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Third-Party & Vendor Risk Management$q$, $q$Workflows for onboarding, assessing, and continuously monitoring vendors and other third parties.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Policy Management$q$, $q$Centralized creation, review, and attestation tracking for organizational policies and procedures.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Compliance Framework Mapping$q$, $q$Pre-mapped controls and evidence structures aligned to frameworks such as SOC 2, ISO 27001, and NIST.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Spark AI$q$, $q$An optional generative AI assistant that helps draft risk content, recommend controls, and summarize evidence.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Reporting & Dashboards$q$, $q$Configurable dashboards and reports for tracking risk posture, control status, and program metrics.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$API & Integrations$q$, $q$An API and connectors to tools such as Slack, Jira, and identity providers for syncing data and notifications.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Automated Notifications$q$, $q$Rule-based alerts and reminders that keep review cycles, attestations, and remediation tasks on track.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Highly configurable no-code builder adapts to evolving GRC program needs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Broad library of pre-built application templates speeds initial deployment$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Connects risks, controls, policies, and vendors within one system of record$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Optional Spark AI features can accelerate drafting and evidence review$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Strong fit for running multiple GRC programs, such as ERM and third-party risk, together$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Pricing is quote-based and generally out of reach for small teams or budgets$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Requires a dedicated administrator to build and maintain workflows effectively$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$No published self-serve pricing or free plan is available$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Initial setup and configuration can take meaningful time to get right$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$May be more platform than needed for a single, narrow compliance use case$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Is LogicGate Risk Cloud free to use?$q$, $q$No. LogicGate does not publish a free plan; pricing is custom and quote-based, provided after speaking with sales.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$What is LogicGate Risk Cloud used for?$q$, $q$It is a no-code GRC platform used to build custom workflows for enterprise risk, third-party/vendor risk, policy management, and compliance programs.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Which compliance frameworks does LogicGate support?$q$, $q$LogicGate offers pre-built content mapped to common frameworks such as SOC 2, ISO 27001, and NIST, alongside custom framework support.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Does LogicGate include AI features?$q$, $q$Yes, LogicGate offers Spark AI, an optional generative AI assistant that can help draft content, recommend controls, and summarize evidence.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$How is LogicGate licensed?$q$, $q$Licensing is based primarily on paid Power User administrators plus the Applications deployed, while standard viewers are generally included at no extra license cost.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Enterprise Risk Management$q$, $q$Building a centralized risk register that links identified risks to controls, owners, and mitigation plans across the business.$q$, $q$Risk management and internal audit teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Third-Party & Vendor Risk Management$q$, $q$Standardizing vendor onboarding, due diligence questionnaires, and ongoing monitoring of third-party relationships.$q$, $q$Procurement, security, and vendor management teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Compliance Program Management$q$, $q$Mapping controls and evidence to frameworks such as SOC 2 or ISO 27001 and tracking audit readiness over time.$q$, $q$Compliance and audit teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$IT & Security Risk Management$q$, $q$Tracking IT and cybersecurity risks, control testing, and remediation workflows in one connected system.$q$, $q$IT, security, and information risk teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Single Application$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["One Risk Cloud Application (e.g., policy management or vendor risk)","Paid Power User administrator licenses","Included standard and external user access","Core no-code workflow builder and reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Multi-Application Program$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["Multiple connected Applications across risk, compliance, and vendor programs","Expanded Power User license count","Cross-application linking of risks, controls, and policies","API access and third-party integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$Enterprise Program$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["Full Risk Cloud application library and custom-built Applications","Optional Spark AI generative assistant","Dedicated implementation and professional services support","Advanced reporting, dashboards, and integration options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LogicGate, now marketed as LogicGate Risk Cloud, is a no-code governance, risk, and compliance (GRC) platform founded in 2015 and headquartered in Chicago. It lets risk, compliance, security, and audit teams build custom workflow applications without writing code.$q$, $q$The platform organizes GRC programs into modular Applications, pre-built templates for use cases like enterprise risk management, third-party and vendor risk, policy management, IT risk, and mapping to compliance frameworks such as SOC 2, ISO 27001, and NIST, which customers can adopt as-is or customize.$q$, $q$More recently, LogicGate added Spark AI, an optional generative AI assistant that helps draft risk narratives, recommend controls, and summarize evidence, layered on top of the platform's core workflow, automation, and reporting engine.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$who-logicgate-is-for$q$, $q$Who LogicGate Is For$q$, 2, ARRAY[$q$LogicGate suits mid-market and enterprise risk, compliance, and security teams that need to run multiple interconnected GRC programs from a single system of record instead of managing them in spreadsheets and disconnected tools.$q$, $q$It is aimed at organizations with a dedicated risk or compliance function, often already familiar with frameworks like NIST, ISO 27001, or SOC 2, that want a configurable platform rather than a rigid, one-size-fits-all product.$q$, $q$Companies anticipating growing compliance obligations, such as new regulations, expanding vendor risk programs, or recurring audits, tend to benefit most, since the no-code builder is designed to adapt as requirements evolve without new development work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Small businesses or startups with a single, narrow compliance need, such as tracking one SOC 2 audit, may find LogicGate's breadth and enterprise-oriented pricing more platform than they actually need.$q$, $q$Teams without any internal risk or compliance ownership, or without budget for a dedicated administrator to build and maintain workflows, may struggle to realize the value of a highly configurable model.$q$, $q$Organizations that want transparent, self-serve pricing or a free plan will need to look elsewhere. LogicGate's pricing is quote-based and typically reaches five or six figures annually, which can be a mismatch for tight-budget teams wanting instant sign-up.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, LogicGate provides a drag-and-drop workflow builder that lets administrators model risk registers, control libraries, and review cycles without code, linking records so a risk automatically connects to related controls, policies, and vendors.$q$, $q$The Risk Cloud application library covers common programs, including enterprise risk management, third-party and vendor risk, IT risk, policy and procedure management, business continuity, and compliance mapping to frameworks like SOC 2, ISO 27001, and NIST, each customizable after deployment.$q$, $q$Reporting dashboards, automated notifications, and integrations, including API access and connectors to tools like Slack, Jira, and identity providers, round out the platform, while Spark AI adds optional generative assistance for drafting content and summarizing evidence.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', $q$the-logicgate-experience$q$, $q$The LogicGate Experience$q$, 2, ARRAY[$q$New customers typically go through guided, sales-assisted onboarding rather than instant self-service sign-up, reflecting the platform's positioning as a configurable enterprise system rather than an off-the-shelf app.$q$, $q$Users generally describe the interface as clean and modern for a GRC tool, with the workflow builder as the standout capability: administrators can reshape forms, fields, and automations as programs mature, though building a program well still takes deliberate setup effort.$q$, $q$Ongoing use centers on a small group of Power Users maintaining the configuration while broader teams interact through simpler forms and dashboards, with LogicGate offering customer success and professional services support to help programs grow over time.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
