INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e3ee3433-997d-4462-9aa7-1e921d116666', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Behind-the-glass observer viewing$q$, $q$Stakeholders can watch live moderated sessions invisibly, without the participant knowing anyone besides the moderator is present.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Private back-channel chat$q$, $q$Observers discuss what they're seeing in a chat that's hidden from the participant while a session is still in progress.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Native iOS and Android participant apps$q$, $q$Dedicated mobile apps capture full-device screen gestures, taps, swipes, camera, and voice for testing native apps and prototypes on real hardware.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Single-click note capture and transcription$q$, $q$Sessions are automatically recorded and transcribed, and researchers can timestamp key moments with a single click as they happen.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$AI Discover$q$, $q$Query across many session recordings conversationally to identify recurring patterns and themes without rewatching every video.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$AI moderation and follow-up prompts$q$, $q$In unmoderated sessions, AI can prompt intelligent follow-up questions when a participant gives a vague or incomplete answer.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Smart Headlines and automated findings$q$, $q$AI generates scannable transcript summaries and surfaces goal-relevant findings automatically, cutting down manual analysis time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Built-in participant recruitment$q$, $q$Invite participants via a shared link or recruit from an integrated pool using demographic, professional, and technical screener criteria.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Highlight reels and shareable clips$q$, $q$Tag key moments and turn them into timestamped clip links that can be shared with stakeholders who weren't in the session.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Supports both moderated and unmoderated research in a single connected platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Dedicated iOS and Android apps make native mobile app and prototype testing straightforward$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Behind-the-glass viewing and back-channel chat let stakeholders observe live sessions without disrupting them$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$AI Discover and automated findings cut down the time spent manually reviewing recordings$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Cloud recording and transcription mean no manual file uploads or session management$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$No permanently free plan; all self-serve tiers require an annual billing commitment$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Entry-level Freelance plan caps sessions and panel participants, which can feel limiting for larger studies$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Enterprise pricing isn't published and requires contacting sales directly$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Lack of monthly billing can be inconvenient for teams with short-term or one-off research needs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Additional session packages and panel participants beyond plan limits add extra recurring cost$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Does Lookback offer a free plan?$q$, $q$No, Lookback does not have a permanently free tier. It offers a free trial with a limited number of sessions, after which teams must move to a paid annual plan to continue.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Does Lookback support testing native mobile apps?$q$, $q$Yes. Dedicated iOS and Android participant apps record full-device screen gestures, camera, and voice, letting teams test native apps and prototypes on real hardware.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Can Lookback be used for unmoderated research?$q$, $q$Yes. Alongside live moderated sessions, Lookback supports unmoderated studies where participants complete self-guided tasks on their own schedule, with recordings and AI summaries available afterward.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$What is AI Discover?$q$, $q$AI Discover is Lookback's feature for conversationally querying across many session recordings to identify recurring patterns and themes, reducing the need to rewatch every video individually.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Is Lookback billed monthly or annually?$q$, $q$Lookback plans are sold as annual commitments rather than monthly subscriptions, spanning Freelance, Team, Insights Hub, and custom-priced Enterprise tiers.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Native mobile app usability testing$q$, $q$Recruit participants to test a native iOS or Android app or prototype on real devices, capturing screen gestures, camera, and voice in one recording.$q$, $q$Mobile product and design teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Live moderated user interviews$q$, $q$Run one-on-one interviews with behind-the-glass observer viewing and back-channel chat so stakeholders can watch and react in real time.$q$, $q$UX researchers and research ops teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Unmoderated remote usability studies$q$, $q$Send self-guided tasks to participants who complete them on their own schedule, with AI-generated summaries ready when the study closes.$q$, $q$Distributed product and UX teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Cross-session insight synthesis$q$, $q$Use AI Discover and automated findings to identify recurring patterns across a large backlog of past research sessions.$q$, $q$Research operations and insights teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Freelance$q$, $q$$299/year$q$, $q$Annual$q$, $q$["10 sessions included","1 panel participant included","Solo seat","Chat support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Team$q$, $q$$1,782/year$q$, $q$Annual$q$, $q$["100 sessions included","10 panel participants included","10 collaborators","Chat support plus security self-assessment"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Insights Hub$q$, $q$$4,122/year$q$, $q$Annual$q$, $q$["300 sessions included","30 panel participants included","30 collaborators","Priority chat and security assessment assist"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, $q$["Unlimited sessions","Custom collaborator and participant allocation","Dedicated CSM, SSO, and custom legal terms","Team training and security audits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lookback is a qualitative user research platform built for planning, running, recording, and analyzing both live moderated sessions and self-guided unmoderated studies. It lets researchers and product teams talk to real users on desktop, web, and native mobile apps, capturing screen activity, camera video, and audio in a single synchronized recording rather than stitching together separate video-calling and screen-recording tools.$q$, $q$Founded in 2013, Lookback grew out of demand for faster, more direct user feedback than traditional lab-based usability testing could offer. Its core idea was letting distributed teams watch and react to real user sessions as they happened, instead of waiting on written reports days or weeks after a study wrapped up, and that live-observation model still underpins how the product is used today.$q$, $q$Over time the platform has layered AI on top of its original live-session tooling: AI-suggested findings tied to stakeholder goals, automated follow-up prompts during unmoderated sessions, and AI Discover for querying and finding patterns across many recordings at once. The result is a hybrid of raw recorded research and higher-level synthesized insight aimed at UX researchers and the product teams who rely on their findings.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$who-lookback-is-for$q$, $q$Who Lookback Is For$q$, 2, ARRAY[$q$UX researchers and research operations teams who run frequent moderated interviews are a core audience. Lookback's behind-the-glass observer viewing, private back-channel chat, and single-click note capture during live sessions are built specifically for researchers who need stakeholders watching in real time without interrupting the conversation with a participant.$q$, $q$Product and design teams building native mobile apps are another strong fit, since Lookback's dedicated iOS and Android apps record full-device screen gestures, camera, and voice during moderated or unmoderated sessions on real hardware. Teams testing prototypes, unreleased builds, or live apps on phones and tablets get capabilities that generic video-call recording tools don't offer, and can do so without needing a physical usability lab or extra recording hardware.$q$, $q$Small-to-midsize product organizations that want one platform covering both moderated interviews and unmoderated, self-guided studies also benefit, particularly research-mature teams that already recruit their own participants or use an integrated panel and want highlight reels, tagged findings, and AI summaries to share results across the organization quickly. Cross-functional stakeholders who need to see raw evidence rather than a written report also gain from the live and asynchronous viewing options.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo builders, students, and very early-stage teams testing on a minimal budget will likely find Lookback a harder sell than lighter-weight or free alternatives, since there is no permanently free tier. Every self-serve plan requires an upfront annual commitment starting in the hundreds of dollars, which is a different cost model than pay-as-you-go recording tools.$q$, $q$Teams whose research is almost entirely quantitative, such as analytics dashboards, surveys, or A/B test reporting, won't get much value from a platform purpose-built around recorded qualitative sessions, transcripts, and highlight reels. Lookback is optimized for watching and analyzing human behavior on video, not for crunching numeric or survey data, so it works best alongside, rather than instead of, quantitative research tooling.$q$, $q$Organizations that need month-to-month billing flexibility should also look elsewhere, since Lookback's plans are sold as annual commitments rather than flexible monthly subscriptions. That structure can be a poor fit for teams running research in short bursts, seasonal cycles, or a single one-off project without ongoing need, even though the Freelance tier is sometimes used informally as a project-by-project option.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$For moderated research, Lookback offers live streaming of every session, behind-the-glass observer viewing so stakeholders can watch invisibly, a private back-channel chat for observers to discuss what they're seeing, and single-click note capture that timestamps observations as the conversation happens, plus automatic recording and transcription of the full session for later review.$q$, $q$For unmoderated research, participants complete self-guided tasks on their own schedule using native iOS and Android apps or a browser, with the apps capturing full-screen gestures, taps, swipes, camera, and voice regardless of device. AI moderation can prompt intelligent follow-up questions when a participant's answer is vague, keeping unmoderated sessions closer in depth to a live interview.$q$, $q$On the analysis side, AI Discover supports conversational querying across many session recordings to surface recurring patterns, Smart Headlines auto-generate scannable transcript summaries, and Automated Findings surface goal-relevant insights without manual review. Teams can then build highlight reels, share timestamped clips as links, tag colleagues in key moments, and export recordings, transcripts, and Discover logs for downstream reporting.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', $q$the-lookback-experience$q$, $q$The Lookback Experience$q$, 2, ARRAY[$q$A typical study starts by defining stakeholder goals, either manually or with Lookback's stakeholder-goal-generation feature, then choosing a moderated or unmoderated format. Participants can be invited via a shared link, recruited through Lookback's built-in recruitment with demographic and screener criteria, or sourced from an integrated participant pool, with scheduling automated for qualified respondents so researchers spend less time on logistics.$q$, $q$During a live session, the moderator talks with the participant while observers watch behind the glass and drop notes or reactions into a private chat, all without the participant seeing that anyone besides the moderator is present. Unmoderated sessions run unattended, with participants working through tasks on the native app or browser while Lookback records everything in the cloud automatically.$q$, $q$Afterward, researchers rewatch or query sessions instead of exporting raw footage into another tool: AI Discover answers questions across a batch of recordings, Smart Headlines summarize each transcript, and Automated Findings groups observations by theme or stakeholder goal. Teams then package the results as highlight reels and timestamped clip links so the wider organization can see evidence, not just conclusions, without sitting through every hour of raw footage themselves.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
