INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('742217b9-34b3-4a6b-ba4a-7592b4fc8b20', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$LookML semantic modeling$q$, $q$A version-controlled modeling language that centralizes metric and join definitions so every report draws from one governed source of truth.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Live, in-database queries$q$, $q$Queries run directly against the connected warehouse (BigQuery, Snowflake, Redshift, and others) instead of a separate cached extract layer.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Explores and Looks$q$, $q$Self-serve exploration interface where business users build and save views without writing SQL themselves.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Dashboards and scheduling$q$, $q$Interactive dashboards with scheduled delivery to email, Slack, or cloud storage destinations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Embedded analytics$q$, $q$APIs and SDKs for embedding governed dashboards and explores directly into external applications and customer-facing products.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Git-based version control$q$, $q$LookML projects integrate with Git workflows, enabling review, rollback, and collaborative development of the data model.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Role-based access control$q$, $q$Granular permissions and content access rules to control what data and dashboards different users and groups can see.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Google Cloud integration$q$, $q$Deep integration with BigQuery and other Google Cloud data services, plus connectivity to a broad range of external databases.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Data actions and workflow automation$q$, $q$Triggers that push data-driven actions into third-party tools when defined conditions are met inside a dashboard or Explore.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Centralized LookML semantic layer keeps metric definitions consistent across every dashboard and team$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Live, warehouse-native queries avoid stale data from separate extract layers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Strong embedding and API support for building customer-facing data products$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Git-based version control brings software engineering discipline to data modeling$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Deep, native integration with BigQuery and the broader Google Cloud ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$No public pricing and no free tier, making cost evaluation slow and quote-dependent$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Learning LookML and structuring a semantic model requires meaningful engineering investment$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Enterprise-oriented licensing can be expensive relative to lighter self-serve BI tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Warehouse query costs (e.g., BigQuery compute) add variable expense on top of platform licensing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Steeper onboarding curve than point-and-click BI tools aimed at non-technical teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Is Looker the same product as Looker Studio?$q$, $q$No. Looker Studio (formerly Google Data Studio) is a separate, free, lightweight reporting tool, while Looker is Google Cloud's enterprise BI platform built around the LookML semantic modeling layer.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$How much does Looker cost?$q$, $q$Google does not publish list prices for Looker; pricing is quote-based and depends on platform edition and user licensing. Third-party estimates suggest costs commonly range from tens of thousands to well over a hundred thousand dollars per year for typical deployments.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Does Looker require a specific data warehouse?$q$, $q$Looker connects to many databases and cloud warehouses, including BigQuery, Snowflake, and Redshift, querying data live rather than requiring a proprietary storage engine.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$What is LookML?$q$, $q$LookML is Looker's declarative modeling language for defining dimensions, measures, and relationships in the underlying data, creating a single governed semantic layer that all reports and dashboards draw from.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Can Looker be embedded into other applications?$q$, $q$Yes. Looker provides APIs and embedding SDKs that let organizations embed governed dashboards and explores directly into their own applications or customer portals.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Enterprise self-serve analytics$q$, $q$Centralizing metric definitions in LookML so business users across departments explore consistent, governed data without needing SQL skills.$q$, $q$Enterprise analytics and business intelligence teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Embedded customer-facing dashboards$q$, $q$Using Looker's APIs and embedding SDKs to white-label analytics inside a SaaS product for end customers.$q$, $q$Software vendors and product teams building data-driven features$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Governed reporting on cloud data warehouses$q$, $q$Running live queries against BigQuery, Snowflake, or Redshift so dashboards always reflect current data instead of stale extracts.$q$, $q$Data engineering teams managing warehouse-native BI$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Cross-team metric standardization$q$, $q$Replacing scattered spreadsheets and conflicting dashboard definitions with a single LookML-defined source of truth for KPIs.$q$, $q$Data platform and operations leaders at mid-market to large companies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Standard$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["One production instance","Includes a set number of Standard and Developer users","Query-based and administrative API call allowances","Suited to smaller organizations or teams under roughly 50 users"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["Expanded user licensing and API limits","Advanced governance and access controls","Scales to larger, multi-team deployments","Priority support options"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Embed$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["Licensing designed for embedding analytics into external applications","API and SDK access for white-labeled dashboards","Usage-based elements tied to embedded end-user volume","Requires direct engagement with Google Cloud sales"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Looker is Google Cloud's enterprise business intelligence and data platform, born from Looker Data Sciences, a Santa Cruz, California startup founded in 2012 and acquired by Google in 2019. Rather than exporting extracts into a proprietary engine, Looker queries data directly in the underlying warehouse, running natively against sources like BigQuery, Snowflake, and Redshift so dashboards reflect live data instead of stale copies.$q$, $q$Its defining feature is LookML, a version-controllable modeling language that lets data teams define metrics, joins, and business logic once in a central semantic layer. Analysts and business users then explore that governed data through Looks, Explores, and dashboards without needing to write SQL, while every number they see stays consistent because it traces back to the same underlying definitions.$q$, $q$Looker is distinct from Looker Studio (formerly Google Data Studio), a free, lightweight reporting tool aimed at individuals and small teams. Looker itself is a heavier, governance-first platform aimed at organizations that need a single, auditable source of truth for metrics across many teams, embedded applications, and data products.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$who-its-for$q$, $q$Who Looker Is For$q$, 2, ARRAY[$q$Looker suits mid-market and enterprise organizations that already run a cloud data warehouse and need a governed semantic layer sitting on top of it. Data engineering and analytics teams that want to codify business logic once in LookML, rather than letting definitions of 'revenue' or 'active user' drift across spreadsheets and dashboards, are Looker's core audience.$q$, $q$It is also a strong fit for companies embedding analytics into their own products or customer portals, since Looker's API and embedding capabilities let software vendors white-label dashboards and explores for end customers without rebuilding a BI stack from scratch.$q$, $q$Organizations with dedicated data teams that can own version control, Git workflows, and LookML modeling get the most value, since the platform rewards investment in a proper semantic layer with long-term consistency and reduced reporting sprawl across the business.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Small businesses, solo analysts, or teams without an engineer who can maintain a modeling layer will likely find Looker's setup overhead disproportionate to their needs. Learning LookML and structuring a semantic model takes real time, and there is no free tier to experiment with first.$q$, $q$Anyone who just needs quick, ad hoc charts from a spreadsheet or a single marketing dashboard is better served by Google's own free Looker Studio, or a lighter self-serve BI tool, since Looker is built around governed, warehouse-native modeling rather than fast one-off reporting.$q$, $q$Budget-constrained teams should also be cautious: pricing is enterprise-oriented and quote-based, with published estimates from third-party sources often landing well into five or six figures annually once platform and per-user licensing, plus warehouse query costs, are combined.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Looker is LookML, a declarative modeling language that centralizes metric definitions, joins, and access rules in Git-versioned files, so every dashboard and Explore draws from the same governed logic instead of duplicated queries. This semantic layer is what differentiates Looker from tools that model dashboards independently.$q$, $q$Looker connects live to modern cloud warehouses rather than requiring data extraction, which means users work against current data and the platform can push computation down to the database engine. On top of that data layer sit Explores for self-serve investigation, Looks and dashboards for saved reporting, and scheduled delivery to email, Slack, or cloud storage.$q$, $q$For technical teams, Looker exposes a full API, embedded analytics SDKs, and integration with Google Cloud services, enabling custom data applications, white-labeled customer-facing dashboards, and workflow automation triggered from data conditions.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$the-looker-experience$q$, $q$The Looker Experience$q$, 2, ARRAY[$q$Using Looker day to day feels different depending on your role. Data teams spend their time in the LookML modeling layer, writing and reviewing model changes through Git pull requests, while business users mostly interact with a browser-based interface of Explores, saved Looks, and dashboards that hide that underlying complexity.$q$, $q$For business users, the experience is largely point-and-click: pick dimensions and measures from an Explore, filter and pivot the results, then save or schedule the view. Because everything is generated from the same governed model, the numbers stay consistent whether someone views a dashboard on the web, in an embedded app, or in a scheduled email export.$q$, $q$The tradeoff is a steeper initial ramp than lighter BI tools: teams typically need onboarding time to structure their first LookML models and warehouse connections before the platform's speed and consistency benefits show up in daily reporting workflows.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Drag-and-drop report builder$q$, $q$Build dashboards and reports visually with charts, tables, and controls, without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Native Google integrations$q$, $q$Connect directly to Google Analytics, Google Ads, Search Console, Sheets, and BigQuery with built-in connectors.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$600+ partner data connectors$q$, $q$Pull in data from non-Google platforms such as Facebook Ads, Salesforce, and HubSpot through connectors built by Google partners.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Data blending$q$, $q$Combine multiple data sources into a single chart or table to build cross-platform metrics.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Interactive charts and controls$q$, $q$Add filters, date-range selectors, and drill-downs so viewers can interact with a report rather than just read it.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Real-time collaborative editing$q$, $q$Multiple users can edit the same report simultaneously, similar to collaborating in Google Docs or Sheets.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Customizable templates$q$, $q$Start from prebuilt templates for common use cases like marketing or web analytics and adapt the theme, layout, and branding.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Sharing, embedding, and scheduled delivery$q$, $q$Share reports via link, embed them on a website, or schedule automatic PDF email delivery to stakeholders.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Looker Studio Pro (paid)$q$, $q$Adds team-based content ownership, project-level access management through Google Cloud, and support with service-level commitments.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Free for the core product with no seat limits on the standard tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Deep, native integration with Google Analytics, Ads, Search Console, and Sheets$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Large connector ecosystem for pulling in data from outside the Google ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Real-time collaborative editing that feels familiar to Google Workspace users$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$No-code, drag-and-drop interface that's approachable for non-technical users$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Performance can lag with very large datasets or heavily blended queries$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Many third-party data connectors require separate paid subscriptions from partner vendors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Customization, formatting, and advanced analytics trail dedicated BI tools like Tableau or Power BI$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Looker Studio Pro is billed per Google Cloud project, which can complicate cost management for agencies with many clients$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Limited support for advanced statistical modeling or predictive analytics compared to full BI platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Is Looker Studio free to use?$q$, $q$Yes. The core Looker Studio product, including report building, native Google connectors, and sharing, is free. Looker Studio Pro is an optional paid add-on for teams that need centralized asset management and support.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$What's the difference between Looker Studio and Looker?$q$, $q$Looker Studio is a free, self-serve reporting and visualization tool aimed at individuals and small teams, while Looker is Google Cloud's separate, paid enterprise business intelligence platform built for governed, large-scale analytics.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Was Looker Studio previously called Google Data Studio?$q$, $q$Yes. The product launched in 2016 as Google Data Studio and was rebranded Looker Studio in 2022 after Google's acquisition of Looker; it is still widely referred to by both names.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$What data sources can I connect to Looker Studio?$q$, $q$Looker Studio natively supports Google Analytics, Google Ads, Search Console, Sheets, and BigQuery, plus hundreds of additional platforms through partner-built connectors.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Do I need coding or design skills to build a report?$q$, $q$No. Reports are built with a drag-and-drop editor, so most users can create a functional dashboard without any coding, though calculated fields offer optional formula-based customization.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Marketing performance reporting$q$, $q$Blend Google Ads, Analytics, and social advertising data into a single dashboard to track campaign performance and ROI.$q$, $q$Digital marketers and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Agency client reporting$q$, $q$Build recurring, branded dashboards that are shared or emailed automatically to clients, reducing manual reporting work.$q$, $q$Digital marketing and SEO agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Executive and operational dashboards$q$, $q$Give internal stakeholders a live, always-current view of key business metrics pulled from Sheets, BigQuery, or other systems.$q$, $q$Business owners and operations teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Web and ecommerce analytics$q$, $q$Track traffic, conversions, and revenue by combining GA4, Search Console, and sales data sources in one interactive report.$q$, $q$Ecommerce and web analytics teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Looker Studio (Free)$q$, $q$$0$q$, $q$Free$q$, $q$["Unlimited reports and dashboards","Native Google connectors (Analytics, Ads, Sheets, BigQuery)","Drag-and-drop report editor with data blending","Sharing, embedding, and scheduled email delivery"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Looker Studio Pro$q$, $q$From $9/user/month$q$, $q$Monthly or annual, billed per Google Cloud project$q$, $q$["Team-based content ownership and asset management","Project-level access controls via Google Cloud IAM","Content migration and ownership transfer tools","Support with service-level commitments"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Looker Studio is Google's free, browser-based data visualization and reporting tool. It launched in 2016 as Google Data Studio, part of the Google Analytics 360 suite, before being rebranded Looker Studio in 2022 following Google's acquisition of the enterprise analytics company Looker. The core product remains free for individuals and teams of any size.$q$, $q$At its core, Looker Studio lets users connect to data sources, blend them together, and build interactive dashboards and reports using a drag-and-drop editor, without writing code. It plugs directly into Google Analytics, Google Ads, Search Console, Sheets, and BigQuery, and can pull in hundreds of other services through partner-built connectors.$q$, $q$Looker Studio should not be confused with Looker, Google Cloud's paid, governed enterprise business intelligence platform. Looker Studio is the lightweight, self-serve reporting layer aimed at marketers, analysts, and small teams, while a separate paid tier, Looker Studio Pro, adds team-oriented asset management and support for organizations that outgrow the free experience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$who-its-for$q$, $q$Who Looker Studio Is For$q$, 2, ARRAY[$q$Digital marketers and agencies are among the heaviest users, relying on Looker Studio to blend Google Ads, Analytics, and social advertising data into recurring client-facing reports without needing a developer or a dedicated BI budget.$q$, $q$Small businesses, startups, and solo analysts benefit from a genuinely free reporting tool that connects natively to GA4, Search Console, and Google Sheets, making it easy to stand up real-time dashboards for traffic, conversions, and campaign performance.$q$, $q$Teams already embedded in the Google Workspace and Google Cloud ecosystem, especially those storing data in BigQuery or Sheets, get the most value, since Looker Studio requires no additional infrastructure and reuses credentials and permissions they already have.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises that need governed, high-performance business intelligence across massive, complex datasets are better served by a full BI platform such as Looker, Power BI, or Tableau, which offer more robust modeling layers and enterprise-grade governance.$q$, $q$Organizations that require pixel-perfect print reporting, advanced statistical or predictive analytics, or heavily customized visual design will find Looker Studio's charting and formatting options comparatively limited next to dedicated BI or data-science tooling.$q$, $q$Companies that depend on many non-Google data sources may find the 'free' appeal erodes quickly, since third-party connectors are often sold separately by partner vendors; agencies managing many clients may also find Looker Studio Pro's per-Google-Cloud-project billing model harder to reason about than a single flat organizational license.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Looker Studio connects to native Google sources (Analytics, Ads, Search Console, Sheets, BigQuery) plus hundreds of partner-built connectors for platforms like Facebook Ads, Salesforce, and HubSpot, and it can blend multiple sources into a single chart or table.$q$, $q$The drag-and-drop report builder offers dozens of chart types, report- and page-level filters, calculated fields, date-range controls, and live multi-user collaborative editing that feels similar to editing a Google Slides or Sheets document.$q$, $q$Reports can be shared via link, embedded on a website, exported as PDF, or delivered on a recurring email schedule. The paid Looker Studio Pro tier layers on team-based content ownership and asset management, project-level access controls tied to Google Cloud, and support with service-level commitments.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$experience$q$, $q$The Looker Studio Experience$q$, 2, ARRAY[$q$The interface mirrors familiar Google Workspace conventions, so anyone comfortable with Sheets or Slides can typically start building a dashboard within minutes, entirely inside the browser with nothing to install.$q$, $q$Performance is solid for small and mid-sized datasets and everyday marketing or operational reporting, but heavily blended queries or very large BigQuery tables can slow rendering, and caching and extraction settings sometimes need tuning to keep dashboards responsive.$q$, $q$Overall, Looker Studio is best understood as a low-friction entry point into data visualization: strong value for cost-conscious teams already in the Google ecosystem, with many organizations eventually graduating to Looker or another enterprise BI platform once governance, scale, or advanced modeling needs grow beyond what the free tool comfortably handles.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
