INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Content calendar$q$, $q$A shared, visual calendar shows every post's status across all connected social accounts, making it easy to plan and track content at a glance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Post ideas & inspiration$q$, $q$Automated prompts based on trending topics, holidays, and platform best practices help teams keep a steady stream of content ideas.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Approval workflows$q$, $q$Structured review and sign-off steps let teams and clients comment on drafts and approve posts before they go live.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$AI assistant$q$, $q$Built-in AI helps generate captions, post copy, and ideas directly inside the content creation workflow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Advanced analytics$q$, $q$Performance reporting tracks engagement and reach across connected networks to inform future content decisions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Unified interactions inbox$q$, $q$Comments and messages from connected social accounts can be viewed and answered from one central inbox.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Bio links$q$, $q$A built-in landing page tool lets brands create a linkable bio page to drive traffic from social profiles.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Ads manager$q$, $q$Facebook and Instagram ad campaigns can be created and managed alongside organic content in the same platform.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Custom branding & roles$q$, $q$Agencies and larger teams can apply custom branding and assign granular roles to manage permissions across brands and clients.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Mobile apps$q$, $q$iOS and Android apps allow teams to review, approve, and manage content and notifications while away from a desktop.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Clean, calendar-centric interface that is easy for non-technical marketers to learn$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Strong approval workflow and commenting tools built for agency-client collaboration$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Built-in post ideas and optimization tips reduce content-planning friction$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Covers scheduling, analytics, ads, and a unified inbox in one platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Supports a broad range of major social networks from a single dashboard$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$No free plan; all paid plans require a subscription after the trial period$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Noticeable price jump between the Starter and Beyond tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Fewer deep social listening and advanced automation options than some enterprise suites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Ad management is limited mainly to Facebook and Instagram$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Higher-tier features like custom roles and branding are locked behind pricier plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Does Loomly offer a free plan?$q$, $q$No, Loomly does not currently offer a free tier. All plans are paid, though a free trial is available without requiring a credit card.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$How much does Loomly cost?$q$, $q$Paid plans start at $65 per month billed monthly, or around $49 per month when billed annually, for the Starter plan covering 12 social accounts and 3 users.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Which social networks does Loomly support?$q$, $q$Loomly supports major networks including Facebook, Instagram, LinkedIn, X, TikTok, Pinterest, YouTube, and Google Business Profile.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Is Loomly good for agencies?$q$, $q$Yes, Loomly's approval workflows, custom roles, and multi-brand support are commonly used by agencies to manage several client accounts from one dashboard.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Does Loomly have a mobile app?$q$, $q$Yes, Loomly offers iOS and Android apps so teams can review content, approve posts, and get notifications on the go.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Agency client content management$q$, $q$Agencies use Loomly to plan, draft, and route content for approval across multiple client brands from a single shared calendar.$q$, $q$Social media and marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Small business content planning$q$, $q$Small business owners rely on Loomly's post ideas and calendar to maintain a consistent posting schedule without a dedicated content team.$q$, $q$Small business owners and solo marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$In-house marketing team collaboration$q$, $q$Marketing teams use approval workflows and commenting to coordinate content review between writers, designers, and managers before publishing.$q$, $q$In-house marketing and brand teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Cross-channel performance tracking$q$, $q$Teams use Loomly's analytics to compare post performance across networks and refine content strategy over time.$q$, $q$Marketing managers and analysts$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Starter$q$, $q$$65/month ($49/month billed annually)$q$, $q$Monthly or annual$q$, $q$["12 social accounts","3 users","Content calendar and scheduling","Approval workflows","AI assistant and advanced analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Beyond$q$, $q$$332/month ($249/month billed annually)$q$, $q$Monthly or annual$q$, $q$["60 social accounts","Unlimited users","Custom branding and custom roles","Hashtag manager","All Starter features included"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, $q$["61+ social accounts","Unlimited users","Priority support","All Beyond features included"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Loomly is a social media management platform built around a shared content calendar, post creation tools, and structured approval workflows. Founded in 2015 and headquartered in New York City, the company has grown into one of the more recognizable names in the social media scheduling space, serving marketing teams, agencies, and small businesses that need a central place to plan, review, and publish content across multiple channels without losing track of who approved what and when.$q$, $q$At its core, Loomly combines scheduling and publishing with brand-specific post ideas, trending topic prompts, and optimization tips that surface as you build a post. Content can be drafted, commented on, approved, and scheduled to networks like Facebook, Instagram, LinkedIn, X, TikTok, Pinterest, YouTube, and Google Business Profile from a single dashboard, with analytics reporting, an ads manager, and a unified interactions inbox layered on top so most day-to-day social work can happen in one place.$q$, $q$Loomly positions itself as a mid-market alternative to heavier enterprise social suites and lighter single-purpose schedulers, aiming to cover the full content lifecycle: ideation, drafting, internal or client sign-off, publishing, and post-performance reporting, without requiring a patchwork of separate tools. That positioning has helped it become a common choice for agencies juggling several client brands as well as internal marketing teams that want more structure than a bare-bones scheduler provides, without the complexity or cost of a full enterprise marketing suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$who-loomly-is-for$q$, $q$Who Loomly Is For$q$, 2, ARRAY[$q$Loomly suits marketing teams and agencies that manage several brands or client accounts and need a shared, visual calendar everyone can see at a glance. Its role-based access and multi-brand support make it easy to keep client work organized without accounts bleeding into one another, which is especially valuable once a team is juggling more than a handful of clients or products at once.$q$, $q$It also works well for small and mid-sized business marketers who want built-in inspiration when they run short on content ideas, since the post-ideas and optimization-tip features are aimed squarely at teams without a large in-house creative department. These prompts can shorten the time it takes to fill out a monthly calendar and reduce the pressure to constantly brainstorm from scratch.$q$, $q$Organizations with a formal review process, such as agencies that need client sign-off before anything goes live, benefit from Loomly's approval workflows and commenting, which reduce the back-and-forth normally handled over email or chat. Teams that already run a structured content-review process, or want to introduce one, tend to adapt to Loomly's model quickly.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo creators and individual influencers who just need to queue posts to one or two accounts may find Loomly more structure and cost than they need, since its approval-workflow-centric design is built for teams rather than single users. A simpler, single-user scheduler is often a better fit and a cheaper one for this kind of workflow.$q$, $q$Large enterprises that require deep social listening, sentiment analysis, or tight CRM and helpdesk integrations may outgrow Loomly's feature set and should evaluate more specialized enterprise social suites before committing, since Loomly's strengths lie more in planning and approvals than in advanced monitoring or customer-service style integrations.$q$, $q$Budget-conscious buyers should also note that Loomly no longer offers a free plan, and the price gap between its entry-level and mid-tier plans is significant, which can make it a harder fit for very small teams managing a large number of accounts or looking for the lowest possible monthly cost.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Loomly's foundation is its content calendar, where posts move through draft, review, and scheduled states across every connected network. Alongside it, Post Ideas surfaces trending topics, holidays, and platform-specific prompts to help teams keep a steady content flow without starting from a blank page every time, and built-in optimization tips flag missing hashtags, mentions, or links before a post ships.$q$, $q$Approval workflows let teams route drafts to specific reviewers, leave threaded comments, and lock down who can publish, which is central to how agencies use the product with clients. Loomly also includes an AI assistant for drafting captions and ideas, plus advanced analytics for tracking engagement and post performance across channels over time.$q$, $q$Beyond scheduling, Loomly offers a unified interactions inbox for replying to comments and messages, a bio-link landing page builder, ad management for Facebook and Instagram campaigns, custom branding, and granular custom roles for larger teams and agency structures. Together these features let a team manage organic content, paid campaigns, and community replies without switching tools constantly, keeping most of a brand's day-to-day social operations under one login.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$the-loomly-experience$q$, $q$The Loomly Experience$q$, 2, ARRAY[$q$Day to day, Loomly presents a clean, calendar-first interface that is generally regarded as approachable for non-technical marketers, with post-building screens that show live previews of how content will look on each network before it goes out, reducing the guesswork around cropping, character limits, and formatting.$q$, $q$Most workflows revolve around drafting a post, tagging a reviewer, resolving comments, and letting the calendar handle timing, which keeps teams from juggling separate documents or spreadsheets for content planning and client approvals. Notifications and status labels make it easy to see what still needs a decision at any point in the week.$q$, $q$Overall, users tend to describe Loomly as easy to onboard and pleasant to use for routine scheduling and collaboration, while power users managing very large account volumes or wanting deeper automation sometimes look to more specialized or enterprise-grade tools to supplement it. For most small-to-mid-sized teams, though, the learning curve is short and the day-to-day experience is straightforward.$q$]::text[], 4);
